import { NextResponse } from 'next/server';
import { getMockSessionUser } from '@/lib/mock-db';

export async function GET() {
  const user = await getMockSessionUser();
  return NextResponse.json({ 
    profile: {
      id: user.id,
      display_name: user.user_metadata.display_name, 
      email: user.email,
      bio: "Local Contributor",
      avatar_url: null
    },
    credits: {
      total_credits: 450,
      credits_earned: 450,
      credits_used: 0
    },
    stats: {
      trees_certified: 15,
      verified_submissions: 5,
      districts_focused: ["Demo District"],
      total_plantings: 15
    }
  });
}
